<?php
if(!defined("IN_ESOTALK"))exit;class Hookable{var $hookedFunctions=array();function callHook($marker,$parameters=array(),$return=false){if(isset($this->hookedFunctions[$marker]) and count($this->hookedFunctions[$marker])){$parameters=is_array($parameters)?array_merge(array(&$this),$parameters):array(&$this);foreach($this->hookedFunctions[$marker] as $function){if(($returned=call_user_func_array($function,$parameters)) and $return)return $returned;}}}function addHook($hook,$function){$this->hookedFunctions[$hook][]=$function;}}class Controller extends Hookable{var $action;var $view;var $title;var $esoTalk;function init(){}function ajax(){}function render(){global $language,$messages,$config;include $this->esoTalk->skin->getView($this->view);}}class Plugin extends Hookable{var $id;var $name;var $version;var $author;var $description;function Plugin(){if(!empty($this->defaultConfig)){global $config;$filename=sanitizeFileName($this->id);if(!file_exists("config/$filename.php"))writeConfigFile("config/$filename.php",'$config["'.escapeDoubleQuotes($this->id).'"]',$this->defaultConfig);include "config/$filename.php";}}function init(){global $versions;if(!isset($versions[$this->id]) or $versions[$this->id]!=$this->version){$this->upgrade(@$versions[$this->id]);$versions[$this->id]=$this->version;writeConfigFile("config/versions.php",'$versions',$versions);}}function settings(){}function saveSettings(){}function upgrade(){}function enable(){}}class Skin{var $name;var $version;var $author;var $views;function init(){}function button($attributes){$attr=" type='submit'";foreach($attributes as $k=>$v)$attr.=" $k='$v'";return "<input$attr/>";}function registerView($view,$file){$this->views[$view]=$file;}function getView($view){return empty($this->views[$view])?"views/$view":$this->views[$view];}}?>
